mapper.select:
WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SEL_CODE, DW_SITE, 구분, 구분_ORD, 도우코드, MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], SITE, 0 AS BOH_MONTH, ISNULL(EOH_MONTH, 0) AS EOH_MONTH FROM DOI_PROD_SUBUL WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND DW_SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SEL_CODE, DW_SITE, 구분, 구분_ORD, 도우코드, MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], SITE, ISNULL(BOH_MONTH, 0) AS BOH_MONTH, 0 AS EOH_MONTH FROM DOI_PROD_SUBUL WHERE 1=1
AND YYYYMM = #{yyyymm}
AND DW_SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
) SELECT YYYYMM, SEL_CODE, DW_SITE, 구분, 구분_ORD, 도우코드, MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], SITE, SUM(BOH_MONTH) AS BOH_MONTH, SUM(EOH_MONTH) AS PREV_EOH_MONTH, SUM(BOH_MONTH) - SUM(EOH_MONTH) AS 차이수량, CASE WHEN SUM(EOH_MONTH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH_MONTH) - SUM(EOH_MONTH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SEL_CODE, DW_SITE, 구분, 구분_ORD, 도우코드, MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], SITE ORDER BY [도우모델], YYYYMM

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH_MONTH, 0) + ISNULL(IN_MONTH, 0) + ISNULL(BONUS_MONTH, 0)) - (ISNULL(EOH_MONTH, 0) + ISNULL(OUT_MONTH, 0) + ISNULL(LOSS_MONTH, 0))) <= 0.01 AND ABS(ISNULL(LOSS_MONTH, 0) - (ISNULL(NG_MONTH, 0) + ISNULL(수율제외_MONTH, 0) + ISNULL(REWORK진행_MONTH, 0))) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH_MONTH, 0) + ISNULL(IN_MONTH, 0) + ISNULL(BONUS_MONTH, 0)) - (ISNULL(EOH_MONTH, 0) + ISNULL(OUT_MONTH, 0) + ISNULL(LOSS_MONTH, 0))) > 0.01 OR ABS(ISNULL(LOSS_MONTH, 0) - (ISNULL(NG_MONTH, 0) + ISNULL(수율제외_MONTH, 0) + ISNULL(REWORK진행_MONTH, 0))) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT, 0 AS WARNING_COUNT FROM DOI_PROD_SUBUL WHERE 1=1
AND YYYYMM = #{yyyymm}
AND DW_SITE = #{site}

WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, DW_SITE, 구분, [도우모델], 0 AS BOH_MONTH, ISNULL(EOH_MONTH, 0) AS EOH_MONTH FROM DOI_PROD_SUBUL WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND DW_SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, DW_SITE, 구분, [도우모델], ISNULL(BOH_MONTH, 0) AS BOH_MONTH, 0 AS EOH_MONTH FROM DOI_PROD_SUBUL WHERE 1=1
AND YYYYMM = #{yyyymm}
AND DW_SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
), ContinuityData AS ( SELECT YYYYMM, SUM(BOH_MONTH) AS BOH_MONTH, SUM(EOH_MONTH) AS PREV_EOH_MONTH, CASE WHEN SUM(EOH_MONTH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH_MONTH) - SUM(EOH_MONTH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, DW_SITE, 구분, [도우모델] ) SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN 상태 = '정상' THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN 상태 = '불일치' THEN 1 ELSE 0 END) AS MISMATCH_COUNT, SUM(CASE WHEN 상태 = '전월 데이터 없음' THEN 1 ELSE 0 END) AS NO_DATA_COUNT FROM ContinuityData
